input.command:
kubectl patch statefulset es-cluster -n elasticsearch --type=strategic --patch='
{
  "spec": {
    "template": {
      "spec": {
        "containers": [
          {
            "name": "metricbeat",
            "image": "docker.elastic.co/beats/metricbeat:7.17.9",
            "args": ["-c", "/etc/metricbeat/metricbeat.yml", "-e", "--strict.perms=false"],
            "env": [
              {
                "name": "ELASTIC_PASSWORD",
                "valueFrom": {
                  "secretKeyRef": {
                    "name": "elastic-password",
                    "key": "password"
                  }
                }
              }
            ],
            "resources": {
              "limits": {"cpu": "200m", "memory": "256Mi"},
              "requests": {"cpu": "100m", "memory": "128Mi"}
            },
            "securityContext": {"runAsUser": 0},
            "volumeMounts": [
              {
                "name": "metricbeat-config",
                "mountPath": "/etc/metricbeat/metricbeat.yml",
                "subPath": "metricbeat.yml"
              },
              {
                "name": "es-certs",
                "mountPath": "/usr/share/elasticsearch/config/certs",
                "readOnly": true
              }
            ]
          },
          {
            "name": "filebeat",
            "image": "docker.elastic.co/beats/filebeat:8.11.1",
            "args": ["-c", "/etc/filebeat/filebeat.yml", "-e", "--strict.perms=false"],
            "env": [
              {
                "name": "POD_NAME",
                "valueFrom": {
                  "fieldRef": {
                    "fieldPath": "metadata.name"
                  }
                }
              }
            ],
            "resources": {
              "limits": {"cpu": "200m", "memory": "256Mi"},
              "requests": {"cpu": "100m", "memory": "128Mi"}
            },
            "securityContext": {"runAsUser": 0},
            "volumeMounts": [
              {
                "name": "filebeat-config",
                "mountPath": "/etc/filebeat/filebeat.yml",
                "subPath": "filebeat.yml"
              },
              {
                "name": "pod-logs",
                "mountPath": "/var/log/pods",
                "readOnly": true
              }
            ]
          }
        ],
        "volumes": [
          {
            "name": "metricbeat-config",
            "configMap": {
              "name": "metricbeat-config"
            }
          },
          {
            "name": "filebeat-config",
            "configMap": {
              "name": "filebeat-config"
            }
          },
          {
            "name": "pod-logs",
            "hostPath": {
              "path": "/var/log/pods",
              "type": "Directory"
            }
          }
        ]
      }
    }
  }
}' 2>&1

